           <h1 className="text-5xl md:text-7xl font-display text-white tracking-tighter mb-1 glow-text animate-glitch">
             WARSAW
           </h1>
           <div className="h-1 w-full bg-term-amber mb-2 shadow-[0_0_10px_#ffb000]"></div>
